#!/usr/bin/env perl

use strict;
use warnings;
use DBI;

my $username = param('username');
my $password = param('password');

my $dsn = 'DBI:mysql:database=mydatabase;host=localhost';
my $dbh = DBI->connect($dsn, 'username', 'password') or die "Connection Error: $!";

my $query = "SELECT * FROM users WHERE username='$username' AND password='$password'";
my $sth = $dbh->prepare($query);
$sth->execute();

my @results;
while (my $row = $sth->fetchrow_hashref()) {
    push @results, $row;
}

print "Content-Type: text/html\n\n";
print "<html><body>";
if (@results) {
    print "Welcome back, " . $results[0]->{username} . "!";
} else {
    print "Invalid username or password.";
}
print "</body></html>";